1	type Cell = [number, number];
2	
3	const cellKey = (x: number, y: number): string => `${x},${y}`;
4	
5	const parseCellKey = (key: string): Cell => {
6	  const [xStr, yStr] = key.split(",");
7	  return [Number(xStr), Number(yStr)];
8	};
9	
10	const neighborOffsets: ReadonlyArray<Cell> = [
11	  [-1, -1], [-1, 0], [-1, 1],
12	  [ 0, -1],          [ 0, 1],
13	  [ 1, -1], [ 1, 0], [ 1, 1],
14	];
15	
16	const neighborsOf = (x: number, y: number): Cell[] =>
17	  neighborOffsets.map(([dx, dy]) => [x + dx, y + dy]);
18	
19	const countLiveNeighbors = (x: number, y: number, liveSet: Set<string>): number =>
20	  neighborsOf(x, y).filter(([nx, ny]) => liveSet.has(cellKey(nx, ny))).length;
21	
22	const survives = (isAlive: boolean, liveNeighbors: number): boolean =>
23	  isAlive ? liveNeighbors === 2 || liveNeighbors === 3 : liveNeighbors === 3;
24	
25	export const nextGeneration = (liveCells: Array<Cell>): Array<Cell> => {
26	  const liveSet = new Set(liveCells.map(([x, y]) => cellKey(x, y)));
27	
28	  const candidateSet = new Set<string>();
29	  for (const [x, y] of liveCells) {
30	    candidateSet.add(cellKey(x, y));
31	    for (const [nx, ny] of neighborsOf(x, y)) {
32	      candidateSet.add(cellKey(nx, ny));
33	    }
34	  }
35	
36	  const result: Cell[] = [];
37	  for (const key of candidateSet) {
38	    const [x, y] = parseCellKey(key);
39	    const liveNeighbors = countLiveNeighbors(x, y, liveSet);
40	    if (survives(liveSet.has(key), liveNeighbors)) {
41	      result.push([x, y]);
42	    }
43	  }
44	
45	  return result;
46	};
